    def __init__(self, config: dict) -> None:
        super().__init__(config)
        self.ai_engine = AISignalEngine(AISignalConfig(signal_file=Path("user_data/data/ai_signals.csv")))
        self.platform = TitanExecutionPlatform()
        self.runtime = TitanRuntimeControlPlane()
        self.runtime_guard_names = [name for name in dir(titan_runtime) if name.startswith("runtime_guard_r")]
        self.runtime_budget_names = [name for name in dir(titan_runtime) if name.startswith("runtime_budget_r")]
        self.execute_names = [name for name in dir(titan_platform) if name.startswith("execute_r")]
        self.validate_names = [name for name in dir(titan_platform) if name.startswith("validate_r")]
        self._bootstrap_roadmap()

    def _bootstrap_roadmap(self) -> None:
        for i, exec_name in enumerate(self.execute_names[:200]):
            exec_fn = getattr(titan_platform, exec_name)
            code = exec_name.replace("execute_", "").upper()
            metrics = {"coverage": 0.85 + ((i % 10) * 0.005), "latency": 180.0 + (i % 15), "stability": 0.92 + ((i % 7) * 0.005)}
            validate_name = f"validate_{code.lower()}"
            is_valid = False
            if validate_name in self.validate_names:
                validate_fn = getattr(titan_platform, validate_name)
                is_valid = bool(validate_fn(metrics))
            if is_valid:
                exec_fn(self.platform, note="auto_bootstrap")

    def _runtime_health_score(self) -> float:
        snapshots = [
            ServiceHealth(name="data", latency_ms=120.0, error_rate=0.004, saturation=0.55),
            ServiceHealth(name="model", latency_ms=160.0, error_rate=0.006, saturation=0.65),
            ServiceHealth(name="execution", latency_ms=140.0, error_rate=0.005, saturation=0.62),
        ]
        for snapshot in snapshots:
            self.runtime.update_health(snapshot)
        guards = []
        for guard_name in self.runtime_guard_names[:300]:
            guard_fn = getattr(titan_runtime, guard_name)
            guards.append(1.0 if guard_fn(180.0, 0.01, 0.50) else 0.0)
        budgets = []
        for budget_name in self.runtime_budget_names[:300]:
            budget_fn = getattr(titan_runtime, budget_name)
            budgets.append(float(budget_fn(4200.0, 52.0, 48.0)["runtime_score"]))
        guard_score = sum(guards) / len(guards) if guards else 0.0
        budget_score = sum(budgets) / len(budgets) if budgets else 0.0
        health_bonus = 1.0 if self.runtime.global_health() else 0.0
        return (guard_score * 0.45) + (budget_score * 0.45) + (health_bonus * 0.10)

    def _policy_score(self, ai_prediction: float) -> float:
        score = 0.0
        for row in self.POLICY_GRID:
            phase_bias = 1.0 if row.phase.endswith("optimization") else 0.92
            aligned = 1.0 if ai_prediction >= row.threshold else -1.0
            score += row.weight * aligned * row.decay * phase_bias
        normalizer = max(len(self.POLICY_GRID), 1)
        return score / normalizer

    def populate_indicators(self, dataframe: DataFrame, metadata: dict) -> DataFrame:
        dataframe["ema_fast"] = ta.EMA(dataframe, timeperiod=12)
        dataframe["ema_mid"] = ta.EMA(dataframe, timeperiod=26)
        dataframe["ema_slow"] = ta.EMA(dataframe, timeperiod=50)
        dataframe["rsi"] = ta.RSI(dataframe, timeperiod=14)
        dataframe["atr"] = ta.ATR(dataframe, timeperiod=14)
        dataframe["atr_pct"] = (dataframe["atr"] / dataframe["close"]).fillna(0.0)
        macd = ta.MACD(dataframe)
        dataframe["macd"] = macd["macd"]
        dataframe["macdsignal"] = macd["macdsignal"]
        dataframe = self.ai_engine.merge_into_dataframe(dataframe)
        dataframe["ai_conviction"] = dataframe["ai_prediction"].abs()
        dataframe["platform_completion"] = self.platform.completion_ratio()
        runtime_score = self._runtime_health_score()
        dataframe["runtime_score"] = runtime_score
        dataframe["policy_score"] = dataframe["ai_prediction"].apply(self._policy_score)
        dataframe["titan_composite"] = (
            (dataframe["ai_prediction"] * 0.45)
            + (dataframe["policy_score"] * 0.20)
            + (dataframe["runtime_score"] * 0.15)
            + (dataframe["platform_completion"] * 0.20)
        )
        dataframe["ai_buy_dynamic"] = (
            self.ai_buy_threshold
            + (dataframe["atr_pct"] * 0.35)
            + ((1.0 - dataframe["runtime_score"]) * 0.08)
            - (dataframe["policy_score"] * 0.05)
        ).clip(lower=-0.05, upper=0.65)
        dataframe["ai_sell_dynamic"] = (
            self.ai_sell_threshold
            - (dataframe["atr_pct"] * 0.25)
            - (dataframe["policy_score"] * 0.08)
        ).clip(lower=-0.80, upper=0.20)
        dataframe["rsi_entry_dynamic"] = (
            45.0
            + ((dataframe["atr_pct"] * 100.0).clip(lower=0.0, upper=14.0) * 0.35)
            - (dataframe["ai_prediction"] * 8.0)
        ).clip(lower=35.0, upper=60.0)
        dataframe["composite_entry_dynamic"] = (
            0.02 + (dataframe["atr_pct"] * 0.30) - (dataframe["policy_score"] * 0.04)
        ).clip(lower=-0.05, upper=0.25)
        dataframe["stoploss_dynamic"] = (
            -0.05
            - (dataframe["atr_pct"] * 1.10)
            + (dataframe["ai_prediction"] * 0.05)
            + (dataframe["policy_score"] * 0.03)
        ).clip(lower=-0.35, upper=-0.03)
        dataframe["risk_off"] = (
            (dataframe["atr_pct"] > (self.max_atr_pct * 1.6))
            | (dataframe["volume"] <= 0)
            | (dataframe["runtime_score"] < 0.48)
        ).astype(int)
        return dataframe

    def populate_entry_trend(self, dataframe: DataFrame, metadata: dict) -> DataFrame:
        dataframe.loc[
            (
                (dataframe["ema_fast"] > dataframe["ema_mid"])
                & ((dataframe["ema_mid"] > dataframe["ema_slow"]) | (dataframe["close"] > dataframe["ema_slow"]))
                & (dataframe["rsi"] > dataframe["rsi_entry_dynamic"])
                & ((dataframe["macd"] > dataframe["macdsignal"]) | (dataframe["ai_prediction"] > dataframe["ai_buy_dynamic"] + 0.10))
                & (dataframe["ai_prediction"] >= dataframe["ai_buy_dynamic"])
                & (dataframe["ai_conviction"] >= self.min_ai_conviction)
                & (dataframe["titan_composite"] > dataframe["composite_entry_dynamic"])
                & (dataframe["risk_off"] == 0)
            ),
            "enter_long",
        ] = 1
        return dataframe

    def populate_exit_trend(self, dataframe: DataFrame, metadata: dict) -> DataFrame:
        dataframe.loc[
            (
                (dataframe["ema_fast"] < dataframe["ema_mid"])
                | (dataframe["rsi"] < (dataframe["rsi_entry_dynamic"] - 8.0))
                | (dataframe["ai_prediction"] <= dataframe["ai_sell_dynamic"])
                | (dataframe["ai_prediction"] <= self.hard_exit_ai)
                | (dataframe["titan_composite"] < (dataframe["composite_entry_dynamic"] - 0.12))
                | (dataframe["risk_off"] == 1)
            ),
            "exit_long",
        ] = 1
        return dataframe

    def custom_stoploss(
        self,
        pair: str,
        trade,
        current_time,
        current_rate: float,
        current_profit: float,
        **kwargs,
    ) -> float:
        if not self.dp:
            return self.stoploss
        dataframe, _ = self.dp.get_analyzed_dataframe(pair, self.timeframe)
        if dataframe is None or dataframe.empty:
            return self.stoploss
        last = dataframe.iloc[-1]
        dynamic_sl = float(last.get("stoploss_dynamic", self.stoploss))
        if current_profit > 0.08:
            dynamic_sl = max(dynamic_sl, -0.02)
        elif current_profit > 0.04:
            dynamic_sl = max(dynamic_sl, -0.035)
        return max(min(dynamic_sl, -0.01), -0.35)
